final:
module top_module (
    input k,
    input w,
    input t,
    output reg obf_d
);
    always @(*) begin
        case ({k, w, t})
            3'b000: obf_d = 1'b1;
            3'b101: obf_d = 1'b1;
            3'b001: obf_d = 1'b0;
            3'b110: obf_d = 1'b1;
            3'b010: obf_d = 1'b0;
            3'b100: obf_d = 1'b1;
            3'b111: obf_d = 1'b1;
            3'b011: obf_d = 1'b1;
        endcase
    end
endmodule
